from machine import Pin, I2C
import ssd1306
import time
import framebuf
import os
import sys


i2c = I2C(sda=Pin(6), scl=Pin(7))
display = ssd1306.SSD1306_I2C(128, 64, i2c)

files = [f for f in os.listdir() if f.endswith("on.py") or f.endswith("ut.py")]
cursor = 0

button_a = Pin(2, Pin.IN, Pin.PULL_UP)
button_b = Pin(3, Pin.IN, Pin.PULL_UP)
button_c = Pin(4, Pin.IN, Pin.PULL_UP)

def pressed(btn):
    if btn.value() == 0:
        time.sleep(0.15)
        return True
    return False

def draw_file_menu():
    display.fill(0)
    display.text("select file:",0,0)
    
    y= 15
    for i, f in enumerate(files):
        prefix = ">" if i == cursor else " "
        display.text(prefix + f, 0, y)
        y += 12
        if y > 60:
            break
    
    display.show()
    
def type(text, x= 0, y=0, delay = 0.05, max_width = 21):
    display.fill(0)
    
    cx, cy  = x, y
    line_height = 10
    
    word_buffer = ""
    
    def draw_char(ch, cx, cy):
            display.text(ch,cx,cy,1)
            display.show()
            time.sleep(delay)
    
    def draw_word(word, cx, cy):
        for ch in word:
            draw_char(ch, cx, cy)
            cx += 6
        return cx, cy
    
    for char in text:
        word_buffer += char
      
        if char == " ":
            word = word_buffer
            word_len = len(word)
            
            if cx + word_len * 6 > x + max_width * 6:
                cx = x
                cy += line_height
            
            cx, cy = draw_word(word, cx, cy)
            word_buffer = " "
    if word_buffer != " ":
        word = word_buffer
        word_len = len(word)
        
        if cx + word_len * 6 > x + max_width * 6:
            cx = x
            cy += line_height
            
        draw_word(word, cx, cy)


