    if pressed(button_c):     
        cursor = (cursor - 1) % len(files)
        
    if pressed(button_a):
        selected = files[cursor]
        
        display.fill(0)
        display.text("Opening:", 0, 0)
        display.text(selected, 0, 12)
        display.show()
        time.sleep(0.5)
        
        try:
            exec(open(selected).read(), {})
            
        except Exception as e:
            display.fill(0)
            display.text("Error:", 0, 0)
